import{_ as e,o as i,c as t,ae as l}from"./chunks/framework.CRIdhvba.js";const h=JSON.parse('{"title":"计算机网络教程 · 第 1 章 走进计算机网络世界","description":"","frontmatter":{"title":"计算机网络教程 · 第 1 章 走进计算机网络世界"},"headers":[],"relativePath":"tutorials/network/index.md","filePath":"tutorials/network/index.md"}'),o={name:"tutorials/network/index.md"};function r(n,a,s,d,p,_){return i(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="第-1-章-·-走进计算机网络世界" tabindex="-1">第 1 章 · 走进计算机网络世界 <a class="header-anchor" href="#第-1-章-·-走进计算机网络世界" aria-label="Permalink to &quot;第 1 章 · 走进计算机网络世界&quot;">​</a></h1><p>计算机网络是让全球计算机互联互通的基础设施。从你打开浏览器访问一个网页，到手机 App 收发消息，都在依赖网络协议栈默默工作。</p><h2 id="_1-1-互联网是如何「连起来」的" tabindex="-1">1.1 互联网是如何「连起来」的？ <a class="header-anchor" href="#_1-1-互联网是如何「连起来」的" aria-label="Permalink to &quot;1.1 互联网是如何「连起来」的？&quot;">​</a></h2><p>从抽象上看，一次网络访问大致会经历：</p><ol><li>客户端应用发起请求（如浏览器输入 URL 并回车）；</li><li>通过 <strong>TCP/IP 协议栈</strong> 将数据切分、封装成报文；</li><li>经过局域网、运营商骨干网、多级路由器转发；</li><li>抵达目标服务器，再由服务器应用处理并返回响应。</li></ol><p>在这个过程中，涉及到 IP、TCP、HTTP、DNS 等一系列协议协同工作。</p><h2 id="_1-2-分层模型的直观理解" tabindex="-1">1.2 分层模型的直观理解 <a class="header-anchor" href="#_1-2-分层模型的直观理解" aria-label="Permalink to &quot;1.2 分层模型的直观理解&quot;">​</a></h2><p>学习网络时最常见的一个抽象是「分层模型」，例如：</p><ul><li>应用层（HTTP、RPC、WebSocket 等）</li><li>传输层（TCP、UDP）</li><li>网络层（IP）</li><li>数据链路层（以太网、Wi-Fi）</li></ul><p>分层的核心价值是：<strong>每层只关心自己的职责</strong>，对下层屏蔽细节，对上层提供清晰接口。</p><h2 id="_1-3-本教程的学习路径" tabindex="-1">1.3 本教程的学习路径 <a class="header-anchor" href="#_1-3-本教程的学习路径" aria-label="Permalink to &quot;1.3 本教程的学习路径&quot;">​</a></h2><p>在之后的章节中，你将从「整体视角」出发，拆解计算机网络的关键主题：</p><ol><li>从一次 HTTP 请求看完整网络传输路径；</li><li>TCP 连接、滑动窗口、拥塞控制等核心机制；</li><li>DNS、CDN、反向代理在互联网访问中的角色；</li><li>常见网络问题的排查思路与抓包分析方法。</li></ol><p>通过这些内容，你可以从「会用」逐步走向「看得懂、能排障」。</p>',14)])])}const P=e(o,[["render",r]]);export{h as __pageData,P as default};
